import '../lib/minor_units.dart';
import '../lib/proportional_allocator.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  var rejectedPrecision = false;
  try {
    MinorUnits.parse('12.345', scale: 2);
  } on FormatException {
    rejectedPrecision = true;
  }
  check(rejectedPrecision,
      'non-zero digits beyond the configured scale are rejected');
  check(MinorUnits.parse('12.3400', scale: 2) == 1234,
      'redundant trailing zeroes do not change an amount');

  final allocation = ProportionalAllocator().allocate(10, [1, 1, 1]);
  check(allocation.length == 3, 'all weighted entries receive a result');
  check(allocation[0] == 4 && allocation[1] == 3 && allocation[2] == 3,
      'an indivisible remainder uses stable input order');
  check(allocation.reduce((left, right) => left + right) == 10,
      'distributed minor units exactly preserve the source total');
}
